package jetbrains.mps.kotlin.dataflow.instructions;

/*Generated by MPS */

import org.jetbrains.annotations.ApiStatus;

/**
 * Boolean state for dataflow states.
 * 
 * Unknown state means that it can be either true or false (both options should be considered).
 * 
 * For instance, if we have a data D with a state true, and a data E with a state unknown, merge two artifacts would result
 * in two artifacts:
 * - true = D + E
 * - false = E
 * Unknown would not be represented in the result since it would clash with true or false and data for true does not equal
 * data for false.
 */
@ApiStatus.Experimental
public enum BooleanState {
  TRUE(),
  FALSE(),
  UNKNOWN();

  public boolean includes(BooleanState state) {
    return this == BooleanState.UNKNOWN || this == state;
  }

  public BooleanState negate() {
    if (this == BooleanState.TRUE) {
      return BooleanState.FALSE;
    } else if (this == BooleanState.FALSE) {
      return BooleanState.TRUE;
    } else {
      return BooleanState.UNKNOWN;
    }
  }

  public boolean booleanValue() {
    if (this == BooleanState.TRUE) {
      return true;
    } else {
      return false;
    }
  }

  @Override
  public String toString() {
    return super.toString().toLowerCase();
  }
}
